import{_ as e,c as t,o as s,aj as o}from"./chunks/framework.guNMSiFm.js";const f=JSON.parse('{"title":"Metadata and Ledger Storage Choices","description":"","frontmatter":{},"headers":[],"relativePath":"guide/configure/metadata-and-store-assets.md","filePath":"guide/configure/metadata-and-store-assets.md","lastUpdated":1777621302000}'),i={name:"guide/configure/metadata-and-store-assets.md"};function r(n,a,l,d,c,h){return s(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="metadata-and-ledger-storage-choices" tabindex="-1">Metadata and Ledger Storage Choices <a class="header-anchor" href="#metadata-and-ledger-storage-choices" aria-label="Permalink to &quot;Metadata and Ledger Storage Choices&quot;">​</a></h1><p>Older Iroha documentation described a separate <code>Store</code> asset type for arbitrary key-value data. The current data model does not use that asset type. Use the following options instead.</p><h2 id="metadata" tabindex="-1">Metadata <a class="header-anchor" href="#metadata" aria-label="Permalink to &quot;Metadata&quot;">​</a></h2><p>Use <a href="/iroha-2-docs/blockchain/metadata.html">metadata</a> for small JSON fields that belong to a ledger object:</p><ul><li>display names and labels</li><li>integration IDs</li><li>small policy flags</li><li>hashes, URIs, CIDs, or SoraFS paths that point to larger payloads</li></ul><p>Metadata is part of world state and is returned with the object that owns it. Keep keys stable, values compact, and permissions explicit. Do not store large documents, logs, or high-churn application state directly in metadata.</p><h2 id="numeric-assets-and-nfts" tabindex="-1">Numeric Assets and NFTs <a class="header-anchor" href="#numeric-assets-and-nfts" aria-label="Permalink to &quot;Numeric Assets and NFTs&quot;">​</a></h2><p>Use <a href="/iroha-2-docs/blockchain/assets.html">assets</a> and <a href="/iroha-2-docs/blockchain/nfts.html">NFTs</a> when the state is value-bearing:</p><ul><li>numeric assets for fungible balances</li><li>NFTs for uniquely owned records</li><li><a href="/iroha-2-docs/blockchain/rwas.html">RWAs</a> and other domain-specific objects when the active data model exposes them</li></ul><p>Assets and NFTs have their own IDs, lifecycle events, transfer behavior, and permission checks. They are better than metadata when ownership, scarcity, or transfer history matters.</p><h2 id="off-chain-data" tabindex="-1">Off-Chain Data <a class="header-anchor" href="#off-chain-data" aria-label="Permalink to &quot;Off-Chain Data&quot;">​</a></h2><p>Use off-chain storage for large or mutable payloads. Store only a stable reference on-chain, such as:</p><ul><li>a content hash</li><li>a URI</li><li>a SoraFS path or manifest reference</li><li>a compact commitment used by an application proof</li></ul><p>This keeps the WSV small while still allowing applications to verify that the off-chain payload matches the on-chain reference.</p><h2 id="choosing-a-location" tabindex="-1">Choosing a Location <a class="header-anchor" href="#choosing-a-location" aria-label="Permalink to &quot;Choosing a Location&quot;">​</a></h2><p>Use this rule of thumb:</p><ul><li>If it is a compact attribute of a ledger object, use metadata.</li><li>If it is value-bearing or transferable, model it as an asset, NFT, or domain-specific object.</li><li>If it is large, high-churn, or application-private, store it outside the WSV and put a verifiable reference on-chain.</li></ul><p>For metadata permissions, see <a href="/iroha-2-docs/reference/permissions.html">Permission Tokens</a>.</p>',18)])])}const m=e(i,[["render",r]]);export{f as __pageData,m as default};
